func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
    // Helper: try inserting ship id into assign idx, return cost delta if feasible, else -1
    tryInsert := func(assignIdx int, shipID int, ori, des Station) float64 {
        origCost := dispatch.Assigns[assignIdx].Cost
        if !dispatch.Assigns[assignIdx].AddShip(shipID, ori, des) {
            return -1
        }
        dispatch.Assigns[assignIdx].GenRoute()
        newCost := dispatch.Assigns[assignIdx].Cost
        if newCost < 0 {
            dispatch.Assigns[assignIdx].RemoveShip(shipID)
            dispatch.Assigns[assignIdx].GenRoute()
            return -1
        }
        delta := newCost - origCost
        // rollback for now; we'll apply the chosen one later
        dispatch.Assigns[assignIdx].RemoveShip(shipID)
        dispatch.Assigns[assignIdx].GenRoute()
        return delta
    }

    // Try each order
    for jj := range oris {
        shipID := total_ship + jj
        bestDelta := math.MaxFloat64
        bestAssignIdx := -1

        // Evaluate all existing non-empty assigns
        for i := 0; i < dispatch.AssignsLen; i++ {
            delta := tryInsert(i, shipID, oris[jj], dess[jj])
            if delta >= 0 && delta < bestDelta {
                bestDelta = delta
                bestAssignIdx = i
            }
        }

        // Also consider a brand-new empty assign if within capacity
        if dispatch.AssignsLen < MAXASSIGNS {
            // Prepare a temporary empty assign slot at dispatch.AssignsLen
            // We'll test by actually adding to the current empty state
            // First save original state of that potential slot
            savedState := dispatch.Assigns[dispatch.AssignsLen]
            // Reset to empty (by constructing zero Assign, but keep fields minimal)
            dispatch.Assigns[dispatch.AssignsLen] = Assign{}
            delta := tryInsert(dispatch.AssignsLen, shipID, oris[jj], dess[jj])
            if delta >= 0 && delta < bestDelta {
                bestDelta = delta
                bestAssignIdx = dispatch.AssignsLen
            }
            // Restore saved state
            dispatch.Assigns[dispatch.AssignsLen] = savedState
        }

        // Apply the best feasible insertion
        if bestAssignIdx >= 0 {
            if !dispatch.Assigns[bestAssignIdx].AddShip(shipID, oris[jj], dess[jj]) {
                // Should not happen because tryInsert succeeded earlier
                // Fallback: force insert into a new empty assign
                if dispatch.AssignsLen < MAXASSIGNS {
                    dispatch.Assigns[dispatch.AssignsLen].AddShip(shipID, oris[jj], dess[jj])
                    dispatch.Assigns[dispatch.AssignsLen].GenRoute()
                    dispatch.AssignsLen++
                }
            } else {
                dispatch.Assigns[bestAssignIdx].GenRoute()
                if bestAssignIdx >= dispatch.AssignsLen {
                    dispatch.AssignsLen = bestAssignIdx + 1
                }
            }
        } else {
