func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx       int
		delta     float64
		success   bool
	}
	nOrders := len(oris)
	for jj := 0; jj < nOrders; jj++ {
		bestCand := cand{idx: -1, delta: 1e18, success: false}
		secondDelta := 1e18
		candidates := make([]cand, 0, dispatch.AssignsLen+1)
		for ii := 0; ii <= dispatch.AssignsLen; ii++ {
			if ii == MAXASSIGNS {
				continue
			}
			tmpAssign := dispatch.Assigns[ii]
			ok := tmpAssign.AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				tmpAssign.GenRoute()
				if tmpAssign.Cost >= 0 {
					baseCost := dispatch.Assigns[ii].Cost
					if baseCost < 0 {
						baseCost = 0
					}
					delta := tmpAssign.Cost - baseCost
					candidates = append(candidates, cand{idx: ii, delta: delta, success: true})
					if delta < bestCand.delta {
						secondDelta = bestCand.delta
						bestCand = candidates[len(candidates)-1]
					} else if delta < secondDelta {
						secondDelta = delta
					}
				} else {
					tmpAssign.RemoveShip(total_ship + jj)
					tmpAssign.GenRoute()
				}
			}
		}
		if bestCand.success {
			regret := secondDelta - bestCand.delta
			if regret < 0 || secondDelta >= 1e17 {
				regret = 0
			}
			finalIdx := bestCand.idx
			if len(candidates) > 1 && candidates[0].success && candidates[1].success {
				maxRegretVal := -1.0
				for _, c := range candidates {
					curRegret := 0.0
					if len(candidates) > 1 {
						sd := 1e18
						for _, other := range candidates {
							if other.idx != c.idx && other.delta < sd {
								sd = other.delta
							}
						}
						if sd < 1e17 {
							curRegret = sd - c.delta
						}
					}
					score := curRegret*0.7 - c.delta*0.3
