						maxRegretVal = score
						finalIdx = c.idx
					}
				}
			}
			dispatch.Assigns[finalIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[finalIdx].GenRoute()
			if finalIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		} else {
			fallbackIdx := dispatch.AssignsLen
			if fallbackIdx < MAXASSIGNS {
				addOk := dispatch.Assigns[fallbackIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
				if addOk {
					dispatch.Assigns[fallbackIdx].GenRoute()
					if dispatch.Assigns[fallbackIdx].Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						dispatch.Assigns[fallbackIdx].RemoveShip(total_ship + jj)
						dispatch.Assigns[fallbackIdx].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

