Greedy insertion with regret heuristic: evaluate each empty or existing assign using a weighted score combining distance increase and time window slack, attempt best insertions first, and always create a new assign if all attempts fail.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	const (
		regretK = 2
		bigPenalty = 1e9
	)
	type cand struct {
		idx     int
		delta   float64
		score   float64
		succeed bool
	}
	nOrder := len(oris)
	if nOrder == 0 || len(dess) != nOrder {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	orderIdx := make([]int, nOrder)
	for i := range orderIdx {
		orderIdx[i] = i
	}
	rand.Shuffle(nOrder, func(i, j int) {
		orderIdx[i], orderIdx[j] = orderIdx[j], orderIdx[i]
	})

	seedAvail := false
	if dispatch.AssignsLen < MAXASSIGNS {
		seedAvail = true
	}

	for _, oi := range orderIdx {
		candidates := make([]cand, 0, MAXASSIGNS*regretK)

		for ai := 0; ai < MAXASSIGNS; ai++ {
			assign := &dispatch.Assigns[ai]

			oldCost := assign.Cost
			ok := assign.AddShip(total_ship+oi, oris[oi], dess[oi])
			if ok {
				assign.GenRoute()
				if assign.Cost >= 0 {
					newCost := assign.Cost
					delta := newCost - oldCost
					timeSlack := computeTimeSlack(assign)
					w := delta / (timeSlack + 1.0)
					candidates = append(candidates, cand{idx: ai, delta: delta, score: w, succeed: true})
				}
				assign.RemoveShip(total_ship + oi)
				assign.GenRoute()
			}
		}

		inserted := false
		if len(candidates) > 0 {
			sort.SliceStable(candidates, func(i, j int) bool {
				if candidates[i].succeed != candidates[j].succeed {
					return candidates[i].succeed
				}
				return candidates[i].score < candidates[j].score
			})
			for k := 0; k < len(candidates) && k < regretK; k++ {
				c := candidates[k]
				assign := &dispatch.Assigns[c.idx]
				if assign.AddShip(total_ship+oi, oris[oi], dess[oi]) {
					assign.GenRoute()
					if assign.Cost >= 0 {
						if c.idx >= dispatch.AssignsLen {
							dispatch.AssignsLen++
						}
						inserted = true
						break
					} else {
						assign.RemoveShip(total_ship + oi)
						assign.GenRoute()
					}
				}
			}
		}

		if !inserted && seedAvail {
			na := dispatch.AssignsLen
			if na < MAXASSIGNS {
				assign := &dispatch.Assigns[na]
				if assign.AddShip(total_ship+oi, oris[oi], dess[oi]) {
					assign.GenRoute()
					if assign.Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						assign.RemoveShip(total_ship + oi)
						assign.GenRoute()
					}
				}
			}
		}

		if !inserted {
			for ai := 0; ai < MAXASSIGNS; ai++ {
				assign := &dispatch.Assigns[ai]
				if assign.StationsLen == 0 && ai >= dispatch.AssignsLen {
					if assign.AddShip(total_ship+oi, oris[oi], dess[oi]) {
						assign.GenRoute()
						if assign.Cost >= 0 {
							dispatch.AssignsLen = ai + 1
							break
						} else {
							assign.RemoveShip(total_ship + oi)
							assign.GenRoute()
						}
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch
}

func computeTimeSlack(a *Assign) float64 {
	slack := 0.0
	tCurr := 0
	st := a.StationCurrent
	for idx := 0; idx < a.StationsLen; idx++ {
		ns := a.Stations[idx]
		if idx > 0 {
			tCurr += int(cal_dis(st, ns)) + 5
		}
		window := 0.0
		if tCurr < ns.TimeStart {
			window = float64(ns.TimeStart - tCurr)
		} else if tCurr > ns.TimeEnd {
			window = -float64(tCurr - ns.TimeEnd)
		}
		slack += window
		st = ns
	}
	if slack < 0 {
		return 0.0
	}
	return slack + 1.0

